+{
+  "$schema": "https://json-schema.org/draft/2020-12/schema",
+  "$id": "https://wezterm-automata.dev/schemas/wa-robot-rules-list.json",
+  "title": "WA Robot Rules List Response",
+  "description": "Schema for the data field when calling 'wa robot rules list'. Lists pattern detection rules.",
+  "type": "object",
+  "required": ["packs", "total_rules"],
+  "properties": {
+    "packs": {
+      "type": "array",
+      "description": "Pattern packs and their rules",
+      "items": {
+        "$ref": "#/$defs/pack"
+      }
+    },
+    "total_rules": {
+      "type": "integer",
+      "minimum": 0,
+      "description": "Total number of rules across all packs"
+    },
+    "enabled_packs": {
+      "type": "array",
+      "description": "List of enabled pack IDs",
+      "items": {
+        "type": "string"
+      }
+    }
+  },
+  "additionalProperties": false,
+  "$defs": {
+    "pack": {
+      "type": "object",
+      "description": "A pattern pack containing detection rules",
+      "required": ["id", "name", "enabled", "rules"],
+      "properties": {
+        "id": {
+          "type": "string",
+          "description": "Pack identifier (e.g., 'core.codex')"
+        },
+        "name": {
+          "type": "string",
+          "description": "Human-readable pack name"
+        },
+        "description": {
+          "type": "string",
+          "description": "Pack description"
+        },
+        "enabled": {
+          "type": "boolean",
+          "description": "Whether the pack is currently enabled"
+        },
+        "version": {
+          "type": "string",
+          "description": "Pack version"
+        },
+        "rules": {
+          "type": "array",
+          "description": "Rules in this pack",
+          "items": {
+            "$ref": "#/$defs/rule"
+          }
+        }
+      },
+      "additionalProperties": false
+    },
+    "rule": {
+      "type": "object",
+      "description": "A pattern detection rule",
+      "required": ["id", "event_type", "severity"],
+      "properties": {
+        "id": {
+          "type": "string",
+          "description": "Full rule ID (e.g., 'core.codex:usage_warning_25')"
+        },
+        "event_type": {
+          "type": "string",
+          "description": "Event type produced (e.g., 'usage.warning')"
+        },
+        "description": {
+          "type": "string",
+          "description": "What this rule detects"
+        },
+        "severity": {
+          "type": "string",
+          "enum": ["info", "warning", "critical"]
+        },
+        "agent_type": {
+          "type": "string",
+          "enum": ["codex", "claude_code", "gemini", "wezterm", "any"],
+          "description": "Agent type this rule applies to"
+        },
+        "extracts": {
+          "type": "array",
+          "description": "Field names extracted by this rule",
+          "items": {
+            "type": "string"
+          }
+        }
+      },
+      "additionalProperties": false
+    }
+  }
+}

@@ -0,0 +1,95 @@
+{
+  "$schema": "https://json-schema.org/draft/2020-12/schema",
+  "$id": "https://wezterm-automata.dev/schemas/wa-robot-rules-test.json",
+  "title": "WA Robot Rules Test Response",
+  "description": "Schema for the data field when calling 'wa robot rules test <content>'. Tests pattern detection on input.",
+  "type": "object",
+  "required": ["input_length", "detections", "elapsed_us"],
+  "properties": {
+    "input_length": {
+      "type": "integer",
+      "minimum": 0,
+      "description": "Length of input content tested"
+    },
+    "detections": {
+      "type": "array",
+      "description": "All patterns that matched the input",
+      "items": {
+        "$ref": "#/$defs/detection"
+      }
+    },
+    "elapsed_us": {
+      "type": "integer",
+      "minimum": 0,
+      "description": "Time taken for pattern detection in microseconds"
+    },
+    "quick_rejected": {
+      "type": "boolean",
+      "description": "True if the input was quick-rejected (no keywords found)"
+    },
+    "packs_tested": {
+      "type": "array",
+      "description": "Pack IDs that were tested",
+      "items": {
+        "type": "string"
+      }
+    }
+  },
+  "additionalProperties": false,
+  "$defs": {
+    "detection": {
+      "type": "object",
+      "description": "A pattern match result",
+      "required": ["rule_id", "event_type", "severity", "confidence"],
+      "properties": {
+        "rule_id": {
+          "type": "string",
+          "description": "Full rule ID that matched"
+        },
+        "event_type": {
+          "type": "string",
+          "description": "Event type produced"
+        },
+        "agent_type": {
+          "type": "string",
+          "enum": ["codex", "claude_code", "gemini", "wezterm", "unknown"]
+        },
+        "severity": {
+          "type": "string",
+          "enum": ["info", "warning", "critical"]
+        },
+        "confidence": {
+          "type": "number",
+          "minimum": 0,
+          "maximum": 1
+        },
+        "extracted": {
+          "type": "object",
+          "description": "Values extracted by the pattern",
+          "additionalProperties": true
+        },
+        "matched_span": {
+          "type": "object",
+          "description": "Where in the input the pattern matched",
+          "properties": {
+            "start": {
+              "type": "integer",
+              "minimum": 0
+            },
+            "end": {
+              "type": "integer",
+              "minimum": 0
+            }
+          },
+          "additionalProperties": false
+        },
+        "match_time_us": {
+          "type": "integer",
+          "minimum": 0,
+          "description": "Time taken for this specific rule in microseconds"
+        }
+      },
+      "additionalProperties": false
+    }
+  }
+}

@@ -0,0 +1,90 @@
+{
+  "$schema": "https://json-schema.org/draft/2020-12/schema",
+  "$id": "https://wezterm-automata.dev/schemas/wa-robot-search.json",
+  "title": "WA Robot Search Response",
+  "description": "Schema for the data field when calling 'wa robot search <query>'. Returns FTS search results.",
+  "type": "object",
+  "required": ["query", "results", "total_matches"],
+  "properties": {
+    "query": {
+      "type": "string",
+      "description": "The FTS5 query that was executed"
+    },
+    "results": {
+      "type": "array",
+      "description": "Matching segments ordered by relevance (BM25)",
+      "items": {
+        "$ref": "#/$defs/search_result"
+      }
+    },
+    "total_matches": {
+      "type": "integer",
+      "minimum": 0,
+      "description": "Total number of matches (may exceed returned results if limited)"
+    },
+    "limit": {
+      "type": "integer",
+      "minimum": 1,
+      "description": "Maximum results returned"
+    },
+    "pane_filter": {
+      "type": "integer",
+      "minimum": 0,
+      "description": "If set, results were filtered to this pane_id"
+    },
+    "time_filter": {
+      "type": "object",
+      "description": "If set, results were filtered to this time range",
+      "properties": {
+        "after": {
+          "type": "integer",
+          "description": "Unix timestamp (ms) - results after this time"
+        },
+        "before": {
+          "type": "integer",
+          "description": "Unix timestamp (ms) - results before this time"
+        }
+      },
+      "additionalProperties": false
+    }
+  },
+  "additionalProperties": false,
+  "$defs": {
+    "search_result": {
+      "type": "object",
+      "description": "A single search result with snippet and metadata",
+      "required": ["segment_id", "pane_id", "captured_at", "snippet"],
+      "properties": {
+        "segment_id": {
+          "type": "integer",
+          "minimum": 0,
+          "description": "Unique segment identifier"
+        },
+        "pane_id": {
+          "type": "integer",
+          "minimum": 0,
+          "description": "Pane the segment was captured from"
+        },
+        "seq": {
+          "type": "integer",
+          "minimum": 0,
+          "description": "Sequence number within the pane"
+        },
+        "captured_at": {
+          "type": "integer",
+          "minimum": 0,
+          "description": "Unix timestamp (ms) when the segment was captured"
+        },
+        "snippet": {
+          "type": "string",
+          "description": "Relevant portion of the segment with match highlights (FTS5 snippet)"
+        },
+        "bm25_score": {
+          "type": "number",
+          "description": "BM25 relevance score (lower is more relevant)"
+        }
+      },
+      "additionalProperties": false
+    }
+  }
+}
